# ─────────────────────────────────────────────────────────────
#  blocks.py  —  REAL DWG GEOMETRY extracted from reference CAD files
#  Each function draws lines/arcs/circles directly from the DWG source,
#  scaled to the user-specified target size.
# ─────────────────────────────────────────────────────────────

def _add_block(doc, name):
    if name in doc.blocks:
        return doc.blocks[name]
    return doc.blocks.new(name)


def _draw_geometry(blk, geo, sx, sy, ox, oy, layer, lw=18):
    """Draw scaled+offset geometry from extracted DWG data."""
    for (s, e) in geo.get('lines', []):
        blk.add_line(
            (ox + s[0]*sx, oy + s[1]*sy),
            (ox + e[0]*sx, oy + e[1]*sy),
            dxfattribs={"layer": layer, "lineweight": lw}
        )
    for a in geo.get('arcs', []):
        blk.add_arc(
            center=(ox + a['cx']*sx, oy + a['cy']*sy),
            radius=a['r'] * min(sx,sy),
            start_angle=a['sa'], end_angle=a['ea'],
            dxfattribs={"layer": layer, "lineweight": lw}
        )
    for c in geo.get('circles', []):
        blk.add_circle(
            center=(ox + c['cx']*sx, oy + c['cy']*sy),
            radius=c['r'] * min(sx,sy),
            dxfattribs={"layer": layer, "lineweight": lw}
        )
    for pts in geo.get('polylines', []):
        scaled = [(ox + p[0]*sx, oy + p[1]*sy) for p in pts]
        blk.add_lwpolyline(scaled, dxfattribs={"layer": layer, "lineweight": lw})


