# ─────────────────────────────────────────────────────────────
#  PUBLIC BLOCK FUNCTIONS
# ─────────────────────────────────────────────────────────────

def define_transformer_block(doc, length, width, kv=11, kva=None, height_mm=None):
    """
    Transformer — draws an exact L x W outer rectangle (for AutoCAD measure),
    then scales and places the DWG detail geometry INSIDE it.
    The outer rectangle is always exactly length x width — no bushing overrun.
    """
    name = f"TRANSFORMER_{length}x{width}"
    blk  = _add_block(doc, name)

    # ── Step 1: Draw exact outer boundary rectangle ───────────────────────
    # This is what the manager measures — always exact L x W
    blk.add_lwpolyline(
        [(0,0),(length,0),(length,width),(0,width),(0,0)],
        dxfattribs={"layer": "TRANSFORMER", "lineweight": 35, "closed": True}
    )

    # ── Step 2: Scale DWG detail to fit INSIDE the outer rectangle ────────
    # Source body: X=50→2750 (span=2700), Y=550→2550 (span=2000)
    # We scale detail to 90% of L x W so it fits with margin inside boundary
    GEO_BODY_X  = 2700.0
    GEO_BODY_Y  = 2000.0
    GEO_BODY_X0 = 50.0    # source body start X
    GEO_BODY_Y0 = 550.0   # source body start Y
    MARGIN      = 0.92     # fill 92% of the box

    sx = (length * MARGIN) / GEO_BODY_X
    sy = (width  * MARGIN) / GEO_BODY_Y

    # Centre the detail inside the outer rectangle
    ox = (length - GEO_BODY_X * sx) / 2 - GEO_BODY_X0 * sx
    oy = (width  - GEO_BODY_Y * sy) / 2 - GEO_BODY_Y0 * sy

    geo = _GEO_TRANSFORMER_2000
    _draw_geometry(blk, geo, sx, sy, ox, oy, "TRANSFORMER", lw=15)

    # ── Step 3: Labels ────────────────────────────────────────────────────
    rating_txt = f"{kva}kVA  " if kva else ""
    blk.add_text(
        f"{kv}kV  {rating_txt}TRANSFORMER",
        dxfattribs={"layer": "LABELS", "height": min(length, width) * 0.07,
                    "insert": (length * 0.5, width * 0.60), "halign": 1}
    )
    dim_txt = f"L={length}  W={width}  H={height_mm if height_mm else 'N/A'}"
    blk.add_text(
        dim_txt,
        dxfattribs={"layer": "LABELS", "height": min(length, width) * 0.055,
                    "insert": (length * 0.5, width * 0.44), "halign": 1}
    )
    return name


def define_transformer_block_cam(doc, length, width, kv=11):
    """Larger transformer (CAM type) — real DWG geometry."""
    name = f"TRANSFORMER_CAM_{length}x{width}"
    blk  = _add_block(doc, name)
    geo  = _GEO_TRANSFORMER_CAM
    all_x = [p[0] for l in geo["lines"] for p in l]
    all_y = [p[1] for l in geo["lines"] for p in l]
    sx = length / (max(all_x) - min(all_x))
    sy = width  / (max(all_y) - min(all_y))
    _draw_geometry(blk, geo, sx, sy, 0, 0, "TRANSFORMER", lw=18)
    blk.add_text(
        f"{kv}kV TRANSFORMER",
        dxfattribs={"layer": "LABELS", "height": min(length, width) * 0.07,
                    "insert": (length * 0.5, width * 0.15), "halign": 1}
    )
    return name


